code = """import json
import re

# Load clinical data
with open(locals()['var_function-call-4978243134760712053'], 'r') as f:
    clinical_data = json.load(f)

# Filter and extract
valid_patients = []
barcode_histology_map = {}
barcodes = []

# Regex for barcode: TCGA-XX-XXXX
barcode_pattern = re.compile(r"(TCGA-[A-Z0-9]{2}-[A-Z0-9]{4})")

for record in clinical_data:
    histology = record.get('histological_type')
    desc = record.get('Patient_description', '')
    
    if not histology:
        continue
    # Exclude histology in brackets
    if histology.strip().startswith('['):
        continue
        
    # Extract barcode
    match = barcode_pattern.search(desc)
    if match:
        barcode = match.group(1)
        barcodes.append(barcode)
        barcode_histology_map[barcode] = histology

# Construct SQL query
# SQLite uses single quotes for strings.
quoted_barcodes = [f"'{b}'" for b in barcodes]
in_clause = ", ".join(quoted_barcodes)
sql_query = f"SELECT ParticipantBarcode, Symbol, normalized_count FROM RNASeq_Expression WHERE Symbol = 'IGF2' AND ParticipantBarcode IN ({in_clause})"

result = {
    "sql": sql_query,
    "mapping": barcode_histology_map
}

print("__RESULT__:")
print(json.dumps(result))"""

